(window.webpackJsonp=window.webpackJsonp||[]).push([[204],{831:function(n,s){n.exports="\x3c!-- \ntitle: Ftp\nsort: \n--\x3e \n\n> debian10\n\n```bash\napt update\n# 安装vsftpd\napt install vsftpd\nvsftpd -versions\n# 启动服务\nsystemctl start vsftpd\n# 开防火墙\nufw allow 20/tcp\nufw allow 21/tcp\n# 备份配置\ncp /etc/vsftpd.conf /etc/vsftpd.conf.orig\n# 配置文件末尾in添加\nvim /etc/vsftpd.conf\n# 重载\nsystemctl restart vsftpd\n# 新建用户\nuseradd -m <user_name>\npasswd\n# 接下来就可以连接了\n```\n\n```conf\nlisten=NO\nlisten_ipv6=YES\nanonymous_enable=NO\nlocal_enable=YES\nwrite_enable=YES\nlocal_umask=022\ndirmessage_enable=YES\nuse_localtime=YES\nxferlog_enable=YES\nconnect_from_port_20=YES\nchroot_local_user=YES\nsecure_chroot_dir=/var/run/vsftpd/empty\npam_service_name=vsftpd\nrsa_cert_file=/etc/ssl/certs/ssl-cert-snakeoil.pem\nrsa_private_key_file=/etc/ssl/private/ssl-cert-snakeoil.key\nssl_enable=Yes\npasv_enable=Yes\npasv_min_port=10000\npasv_max_port=10100\nallow_writeable_chroot=YES\nssl_tlsv1=YES\nssl_sslv2=NO\nssl_sslv3=NO\n```\n\n"}}]);